import 'package:flutter_test/flutter_test.dart'; import 'package:nomad/models/message.dart'; group('Message', () { test('user factory sets role', () { expect(Message.user('hi').role, 'user'); }); test('assistant factory sets role', () { expect(Message.assistant('hello').role, 'assistant'); }); test('toolResult factory sets metadata', () { final m = Message.toolResult(name: 'calc', result: '42'); expect(m.role, 'tool_result'); }); });
